{"command": "cd /tmp/sv-f4e06753665047edb7017140587856ec/advanced-multi-complexity && python3 -c "
import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw['topLevelPackages']:
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], av))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]:20} {c[1]:8} {c[2]:50} {c[3]:10} -> {c[4]:10}')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]:20} {u[1]:8} {u[2]:50} {u[3]:10}')
"", "description": "Compare baseline vs after-cpm packages", "initial_wait": 10}
